#include <bits/stdc++.h>
using namespace std;
int n,vis[200005],len,lenb,x;
struct kuai{
	int l,r,v;
}a[200005],b[200005];
int main(){
	cin>>n;
	a[0].v=b[0].v=-1;
	for(int i=1;i<=n;i++){
		cin>>x;
		if(x==a[len].v)a[len].r=i;
		else a[++len]={i,i,x};
	}
	while(len>0){
		for(int i=1;i<=len;i++){
			cout<<a[i].l<<' ';
			vis[a[i].l]=1;
			while(a[i].l<=a[i].r && vis[a[i].l])a[i].l++;
		}
		cout<<endl;
		lenb=0;
		for(int i=1;i<=len;i++){
			if(a[i].l<=a[i].r){
				if(a[i].v==b[lenb].v)b[lenb].r=a[i].r;
				else b[++lenb]=a[i];
			}
		}
		len=lenb;
		for(int i=1;i<=len;i++)a[i]=b[i];
	}
	return 0;
}
